// COMPLETE, COMPILABLE C code
#include <stdio.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        long long dp[N];
        dp[0] = 1;
        for (int i = 1; i < N; i++) {
            dp[i] = 0;
            for (int j = 0; j < i; j++) {
                if (i - j <= A[j] && i - j >= 1) {
                    dp[i] = (dp[i] + dp[j]) % MOD;
                }
            }
        }
        long long ans = 0;
        for (int i = 0; i < N; i++) {
            ans = (ans + dp[i]) % MOD;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

