    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            long[] dp = new long[N];
            dp[0] = 1;
            for (int i = 1; i < N; i++) {
                dp[i] = 0;
                for (int j = 0; j < i; j++) {
                    if (i - j <= A[j] && i - j >= 1) {
                        dp[i] = (dp[i] + dp[j]) % 1000000007;
                    }
                }
            }
            long ans = 0;
            for (int i = 0; i < N; i++) {
                ans = (ans + dp[i]) % 1000000007;
            }
            System.out.println(ans);
